insert into public.study_notes (banner, bullets, sort_order)
values
('TOPIC 38: ANAESTHETIC GASES', '["Two classes: volatile liquid anaesthetics (halothane, isoflurane, sevoflurane, desflurane) and gaseous anaesthetics (nitrous oxide).", "Mechanism: mainly enhance inhibitory GABA-A transmission and/or inhibit excitatory NMDA transmission in the CNS → reversible loss of consciousness.", "Delivered via anaesthetic machine + vaporiser, mixed with O2 (± air/N2O), through face mask, LMA or ETT.", "Complications: hypotension, respiratory depression, laryngospasm/bronchospasm, nausea/vomiting, hepatotoxicity, malignant hyperthermia.", "Malignant hyperthermia = rare life-threatening hypermetabolic reaction (volatile agents/succinylcholine) in genetically susceptible patients — rapid temp rise, muscle rigidity, tachycardia, rising EtCO2. Treat with IMMEDIATE dantrolene + active cooling + stop trigger agent + 100% O2.", "Nursing role: prepare/check resuscitation equipment, continuous vital sign + EtCO2 monitoring, watch for early malignant hyperthermia signs.", "Safety: scavenging systems, adequate theatre ventilation, regular circuit leak checks to limit staff waste-gas exposure."]'::jsonb, 41),
('TOPIC 39: POST-ANAESTHETIC (WASTE) GASES', '["Waste gases = residual anaesthetic gas escaping into theatre/recovery room air instead of being delivered to the patient or scavenged.", "Sources: circuit/machine leaks, poor mask fit, patient exhalation during recovery, vaporiser filling, inadequate scavenging.", "Chronic occupational exposure effects: headache, fatigue, irritability; prolonged high exposure linked in some studies to reproductive, hepatic or renal effects.", "Prevention = 3 pillars: scavenging systems, adequate room ventilation (sufficient air exchanges/hr), regular equipment leak checks/maintenance.", "Recovering patients still exhale anaesthetic gas — recovery-room monitoring for sedation/respiratory depression continues until fully awake.", "Nurse''s role: confirm scavenging equipment works before use, stay alert to exposure symptoms in self/colleagues, join routine ventilation/equipment checks."]'::jsonb, 42),
('TOPIC 40: POST-ANAESTHETIC CARE OF SURGICAL PATIENTS (PACU)', '["PACU care runs from arrival in recovery until the patient is stable enough for ward/ICU transfer; admit anyone who had GA, regional anaesthesia, or significant sedation.", "Immediate assessment = ABC approach: airway, breathing (rate/effort/SpO2), circulation (HR/BP/perfusion), level of consciousness, wounds/drains, temperature.", "Airway: position unconscious patients laterally/semi-prone (aspiration risk), suction PRN, give O2, watch for laryngospasm/obstruction.", "Neuro check especially important after spinal/epidural — confirm sensory/motor return follows the expected pattern.", "Common complications: airway obstruction, hypoxia, hypotension, haemorrhage, hypothermia, nausea/vomiting, delayed emergence, arrhythmias, urinary retention.", "Discharge criteria: stable vitals, adequate consciousness, satisfactory pain control, no active bleeding, adequate SpO2.", "Post-thyroidectomy emergency: neck swelling + stridor = wound haematoma compressing airway — sit patient up, high-flow O2, open wound at bedside to release haematoma if instructed (keep a suture-removal kit at the bedside of every post-thyroidectomy patient).", "Post-op haemorrhage red flags: restlessness, falling BP, rising HR, soaked dressing — firm pressure/reinforce dressing, increase IV fluids, urgent bloods + crossmatch, second large-bore IV line, prepare for possible return to theatre."]'::jsonb, 43),
('TOPIC 41: NURSING INFORMATICS & ICT IN CRITICAL CARE', '["Computer hardware: CPU = processing (control unit + ALU); RAM = volatile working memory; ROM = permanent, unchangeable; secondary storage (hard disk, USB, optical disk) = long-term.", "Software split: system software (OS — runs the machine) vs. application software (end-user programmes, e.g. an EHR charting app) vs. utility software (antivirus, backup tools).", "File processing types: batch (grouped, processed later), on-line/real-time (processed instantly), multi-user (many staff concurrently).", "Nursing Information System = manages nursing-specific data (care plans, assessments, documentation); Hospital Information System = integrates clinical + administrative + financial data hospital-wide.", "EHR/computer-based records benefit: legibility, faster retrieval, easier cross-provider data sharing — but need authentication, access control and audit trails to protect confidentiality.", "Telemedicine = delivering care remotely via telecommunications; growing role in specialist consultation and patient education.", "Diagnostic devices (US, CT, MRI) vs monitoring devices (oximeter, cardiac monitor) vs treatment devices (radiotherapy, physiotherapy) — know which bucket a device falls into."]'::jsonb, 44),
('TOPIC 42: APPLIED PHARMACOLOGY — DRUG CLASSES IN ICU', '["Resuscitative drugs: adrenaline (epinephrine) 1mg IV every 3–5min in cardiac arrest; amiodarone for shockable rhythms refractory to defibrillation.", "Vasopressors/inotropes: noradrenaline = first-line in septic shock; dobutamine = inotrope of choice in cardiogenic shock/low cardiac output.", "Sedation & analgesia: propofol/midazolam for sedation, fentanyl/morphine for analgesia — always titrate to a validated sedation scale (e.g. RASS) to avoid over-sedation.", "Neuromuscular blockers (e.g. vecuronium, atracurium) paralyse but do NOT sedate — always give with adequate sedation/analgesia first.", "Bronchodilators: salbutamol (beta-2 agonist) and ipratropium (anticholinergic) for bronchospasm; steroids (hydrocortisone) reduce airway inflammation.", "Mucolytics (e.g. acetylcysteine) thin secretions; antibiotics are chosen empirically first, then narrowed once culture/sensitivity results return.", "Drug overdose/poisoning: activated charcoal binds many oral toxins if given early; specific antidotes exist for select drugs (e.g. naloxone for opioids, flumazenil for benzodiazepines, N-acetylcysteine for paracetamol).", "Drug calculation safety: always double-check weight-based doses and infusion-pump rate calculations against a second nurse/pharmacist in critical care."]'::jsonb, 45),
('TOPIC 43: ETHICO-LEGAL ISSUES IN CRITICAL CARE NURSING', '["Core ethical principles: autonomy (right to self-determination), beneficence (act in patient''s best interest), non-maleficence (do no harm), justice/fairness, confidentiality, fidelity, veracity (honesty).", "Informed consent requires: adequate information, patient capacity to understand, and voluntary agreement without coercion.", "Negligence = 4 elements must all be proven: duty of care, breach of that duty, harm/damage, and breach directly causing the harm.", "Doctrine of Res Ipsa Loquitur (''the thing speaks for itself'') — negligence may be presumed when an injury couldn''t normally occur without someone''s negligence (e.g. a retained surgical instrument).", "Good Samaritan Laws protect a healthcare worker who provides emergency assistance in good faith outside their normal duty, from certain liability.", "End-of-life: Advance Directives state a patient''s wishes in advance; DNR (Do-Not-Resuscitate) orders must be clearly documented and communicated to the whole team.", "Documentation legal principle: ''if it wasn''t documented, it wasn''t done'' — accurate, timely, factual charting is a nurse''s main legal protection.", "Special legal situations: mentally-disturbed, intoxicated, and attempted-suicide patients raise unique consent/capacity issues; animal bites and gunshot/stab wounds are typically reportable to police."]'::jsonb, 46),
('TOPIC 44: PRINCIPLES OF MANAGEMENT & TEACHING', '["5 management functions: Planning, Organising, Staffing, Directing, Controlling (accounting/budgeting, discipline, performance evaluation fall under Controlling).", "Leadership styles: autocratic (leader decides alone), democratic (team involved in decisions), laissez-faire (hands-off) — critical emergencies often need a more autocratic/directive style.", "Delegation: authority can be delegated, but accountability for the outcome stays with the delegating nurse (the ''5 Rights of Delegation'': right task, circumstance, person, direction/communication, supervision).", "Risk management cycle: identify risk → analyse/prioritise → develop a control plan → implement → monitor/review; incident reporting is central to this cycle.", "Adult learning principles (andragogy): adults learn best when the content is relevant, problem-centred, builds on prior experience, and they are involved in planning their own learning.", "Health education/teaching cycle: assess learning needs → set objectives → select teaching method → deliver → evaluate understanding (e.g. teach-back).", "Motivation theories relevant to staff management: Maslow''s hierarchy of needs, Herzberg''s two-factor theory (hygiene factors vs true motivators)."]'::jsonb, 47),
('TOPIC 45: DISASTER & EMERGENCY NURSING', '["Disaster triage uses START (Simple Triage And Rapid Treatment) or similar systems to sort casualties into categories: immediate (red), delayed (yellow), minor (green), expectant/deceased (black).", "Mass casualty principle: ''greatest good for the greatest number'' — resources go where they''ll save the most lives, not necessarily to the sickest individual first.", "Disaster phases: mitigation → preparedness → response → recovery — nursing roles differ at each phase.", "Golden Hour of Trauma: the first 60 minutes after major trauma are critical for survival — rapid ABCDE assessment and definitive care/transfer minimise mortality.", "ABCDE primary survey order in any emergency: Airway (with C-spine control), Breathing, Circulation (with haemorrhage control), Disability (neuro status), Exposure/Environment.", "Disaster nursing roles: rapid triage, on-scene stabilisation, coordination with emergency services, psychological first aid, and clear documentation/handover under pressure.", "Personal/staff safety comes first in any disaster response — a nurse who becomes a casualty adds to the problem rather than helping solve it."]'::jsonb, 48),
('TOPIC 46: LABORATORY SCIENCES — HAEMATOLOGY, TRANSFUSION & INFECTION CONTROL', '["Blood transfusion basics: always check ABO/Rh compatibility and patient ID at the bedside with a second checker; stop immediately and treat as a suspected reaction if fever, chills, back pain, or hypotension develop during transfusion.", "Sickle cell crisis management: aggressive hydration, oxygen, analgesia (often opioids), and treating any precipitating infection.", "DIC (Disseminated Intravascular Coagulation) = simultaneous widespread clotting AND bleeding — watch for oozing from IV sites plus organ dysfunction from microthrombi; manage the underlying cause plus blood product support.", "Common ICU-acquired pathogens: MRSA, Pseudomonas aeruginosa, Klebsiella, Candida — device-associated infections (VAP, CLABSI, CAUTI) are the main targets of ICU infection-prevention bundles.", "Sterilisation (kills ALL microorganisms including spores, e.g. autoclaving) vs. disinfection (kills most pathogens but not necessarily spores) — know which is needed for which equipment.", "Culture and sensitivity testing guides antibiotic choice — always send cultures BEFORE starting antibiotics whenever possible, then start empiric therapy while awaiting results.", "Antibiotic prophylaxis timing for surgery: ideally given within 60 minutes before incision, and stopped within 24 hours post-op for most clean procedures to reduce resistance risk."]'::jsonb, 49)
